{
  "name": "Indiana LIHEAP (Energy Assistance Program - EAP)",
  "eligibility": {
    "age": null,
    "income_limits": "60% of State Median Income (60 SMI), based on most recent three months of income. For PY2026 (Oct 2025-Apr 2026), monthly limits by household size: 1: $2,796; 2: $3,659; 3: $4,517; 4: $5,377; 5: $6,238; 6: $7,098; 7: $7,259; 8: $7,421. For 10+ members, based on 150% Federal Poverty Guidelines.[1][6]",
    "asset_limits": "No asset limits mentioned in program guidelines.[1]",
    "other_requirements": ["Indiana resident", "Household must include proof of income for all members 18+", "Processed by Local Service Provider (LSP) per county"][1][3][4]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment to help with heating and electric bills (exact amount not specified; varies by funding, household needs, and LSP determination). Also provides energy moratorium protection from Dec 1, 2025 to Mar 15, 2026 (no disconnection for eligible clients).[1][6]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: https://ihcda.rhsconnect.com/portal/Account/Login", "Phone/In-person/Mail: Contact Local Service Provider (LSP) for your county via https://www.in.gov/ihcda/homeowners-and-renters/low-income-home-energy-assistance-program-liheap/ county map", "Example LSP: Area IV Agency (Boone County) - (765) 447-7683, 1600 W Main St, Lebanon, IN 46052"][1][3][4],
    "processing_time": "14 days for in-person appointments; 55 days for mail/drop-off/fax/email/online/proxy (timelines start Nov 1, 2025, even for early submissions unless crisis).[1]",
    "waitlist": "Not mentioned; funds limited by season (Oct 1, 2025-Apr 20, 2026).[1]",
    "forms": ["PY2026 EAP Application (English/Spanish, black ink only); Request for Earnings form if needed; printable from LSP sites or online portal.[1][4]"],
    "documents": ["Proof of income (3 months): paystubs, full Social Security/SSI/VA benefit letter (all pages, no redactions) or bank statement, pension award letter, Form 1040 with self-employment schedules, Uplink printout (no screenshots)."][4]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available to all Indiana counties via local LSPs.",
    "regional_variations": "Administered by different Local Service Providers (LSPs) per county, which may have varying processing, intake sites, and availability. Use county map on IHCDA site to find specific LSP.[1][3]",
    "offices_or_providers": ["County-specific LSPs, e.g., Area IV Agency for Boone County: (765) 447-7683; LCCS for Lake/Jasper/Newton/Pulaski/Starke Counties; CoAction for others. Full list via IHCDA county map."][1][3][4][6]
  },
  "official_source": "https://www.in.gov/ihcda/homeowners-and-renters/low-income-home-energy-assistance-program-liheap/",
  "gotchas": ["No age requirement—open to all qualifying households, not just elderly (separate programs like SILVER for Seniors 60+ via utilities).[2]", "Income based on gross 3-month average, requires full unredacted docs (e.g., all SS letter pages).[4]", "Processing starts Nov 1 even for Oct 1 apps (unless crisis); apply early as funds deplete.[1][6]", "Must contact county LSP for in-person/mail— not centralized.[1]", "One-time benefit per season, not ongoing.[1]"],
  "data_shape_notes": "County-based LSP administration with varying providers; income at 60 SMI (higher than some states' 150% FPG); seasonal with moratorium protection; no asset test or age limit."
}

{
  "name": "Indiana SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits for core SHIP counseling services; available to all Medicare-eligible individuals, family members, and caregivers. SHIP mentions potential qualification for additional help with medical costs (not core services) if income is less than $2,500 per month and assets are limited, but no specific asset details or table provided.[3]",
    "asset_limits": "No asset limits for core counseling; limited assets referenced vaguely for extra medical cost help, but not defined (e.g., what counts or exemptions not specified).[3]",
    "other_requirements": ["Must be eligible for Medicare (or soon to be), or be a family member/caregiver of a Medicare beneficiary.[2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, impartial, one-on-one counseling and education on Medicare (Parts A, B, D), Medicare Supplement (Medigap), Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB, SLMB, QI), Low-Income Subsidy (Extra Help), prescription drug assistance, Medicaid, claims filing, appeals, and plan enrollment/comparison. Provided by trained, certified volunteer counselors.[3][7][8][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide toll-free line via Indiana Department of Insurance (specific number not in results; use shiphelp.org locator or 877-839-2675 for general SHIP).[5][6]", "Website: https://www.in.gov/ship/ for information and contacts.[3]", "In-person or phone via regional providers (e.g., CICOA for Central Indiana at (317) 803-6131; Area IV Agency for West Central Indiana).[8][9]", "No formal application or specific form required; contact for counseling appointment.[3]"],
    "processing_time": "Immediate counseling available by phone or in-person; no formal processing as it's not an enrollment program.[2][3]",
    "waitlist": null,
    "forms": ["None required for SHIP counseling.[3]"],
    "documents": ["No specific documents needed for counseling; may request Medicare card or insurance details for personalized advice.[3][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide via Indiana Department of Insurance.[3][5]",
    "regional_variations": "Delivered through regional providers/aging agencies (e.g., CICOA in Central Indiana, Area IV Agency in West Central Indiana) with local counselors, but services standardized.[8][9]",
    "offices_or_providers": ["Indiana Department of Insurance, 311 West Washington Street, 2nd Floor, Indianapolis IN 46204 (state office).[5]", "Regional: CICOA (Central IN), Area IV Agency (West Central IN).[8][9]"]
  },
  "official_source": "https://www.in.gov/ship/",
  "gotchas": ["Not a financial aid or healthcare program—provides counseling only, not direct payments or services; confuses with Medicare Savings Programs (MSPs) or Medicaid, which SHIP helps apply for separately.[3][7]", "Volunteers handle counseling, so availability may depend on local schedules.[3]", "For extra cost help mentioned ($2,500/month income), details vague—refer to separate programs like MSPs.[3][6]", "Contact 3 months before Medicare eligibility for best prep.[2]"],
  "data_shape_notes": "no income test for counseling; service-based only with volunteer delivery via regional aging agencies; distinguishes from income-tested programs like MSPs or Medicaid that it counsels on"
}

{
  "name": "Meals on Wheels (Indiana)",
  "eligibility": {
    "age": null,
    "income_limits": "No statewide income limits; some providers offer reduced rates for SNAP, SSDI, Medicaid Disability, SSI, Energy/Trustee Assistance, Veterans, or Veteran spouses. No specific dollar amounts or household tables provided.",
    "asset_limits": "No asset limits mentioned across providers.",
    "other_requirements": ["Physically or mentally unable to prepare meals due to illness, disability, or being homebound (varies by provider; some require homebound status, others do not)", "Residency in provider's delivery zone or eligible zip codes", "Dietary prescription from physician often required", "Some require inability to shop/prepare meals or mobility challenges"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals (medically tailored for dietary restrictions like diabetes, heart healthy, low-sodium, renal; 5 meals per week typical, but varies by need: daily or few days/week). Minimum 2-week service commitment. Friendly visit and wellness check included.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Online form (e.g., mealsonwheelsindy.org/apply/, mealsonwheelshc.org/services/ form)", "Phone: Central IN (317) 252-5558; Hamilton County (317) 776-7159", "Mail: e.g., Meals on Wheels of Central Indiana, 708 E. Michigan St., Indianapolis, IN 46202 (with check/money order for application fee + first 2 weeks)", "In-person: Contact local provider office"],
    "processing_time": "Typically less than 1 week (Central IN); 5-7 business days after application/payment (some providers)",
    "waitlist": "Generally no waitlist, but temporary waitlists possible in Marion County/other areas per funding (Central IN policy)",
    "forms": ["Client application (online/printable via provider sites)", "Financial Assistance Request form (Hamilton County, if needed)"],
    "documents": ["Proof of age/residence/medical info (some)", "Financial docs (if seeking reduced rate)", "Dietary prescription from physician", "Payment for $5 application fee + first 2 weeks meals (non-refundable; check/money order/credit/debit/EBT)"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to provider delivery zones/zip codes (e.g., Central IN specific zips like 46201-46208; Hamilton County service area)",
    "regional_variations": "Operated by local providers with differences: Central IN no age req., open to all, fee-based with subsidies; Hamilton County no age/income req., physician dietary Rx req.; Northwest IN no age/income req. Contact local Area Agency on Aging for specifics.",
    "offices_or_providers": ["Meals on Wheels of Central Indiana (Indianapolis/Marion County)", "Meals on Wheels Hamilton County", "Meals on Wheels of Northwest Indiana", "Local Area Agencies on Aging"]
  },
  "official_source": "No single statewide .gov site; primary via in.gov/fssa/ompp (Medicaid-related) or local providers; find via mealsonwheelsamerica.org/find-meals-and-services/",
  "gotchas": ["Not a single statewide program—must contact local provider for zone eligibility", "Fees required upfront ($5 app + 2 weeks meals, non-refundable minimum commitment)", "Dietary prescription often needed from doctor", "Car ownership or ability to leave home may disqualify in some areas", "Temporary waitlists possible despite 'no waitlist' claims", "Medicaid waivers (e.g., Aged/Disabled) may provide free meals via partners like Mom's Meals—check case manager"],
  "data_shape_notes": "Decentralized by local providers/counties with no uniform statewide eligibility/income test; fee-for-service model with subsidies rather than free-for-all; delivery zone-restricted; no age requirement at many providers"
}

{
  "name": "Indiana Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of an Indiana nursing home or licensed assisted living facility (not home care services)."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to promote and protect resident rights under federal and state law; regular facility visits by staff and volunteer ombudsmen; investigation and resolution of complaints; representation at involuntary discharge hearings; assistance establishing family councils; resident-directed support.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-622-4484 or 317-232-7134", "Email: via state ombudsman contact", "Mail: Office of the Long Term Care Ombudsman, 402 West Washington Street, Room W451, Post Office Box 7083, MS 27, Indianapolis, Indiana 46207-7083", "Online: File complaint via Indiana State Department of Health complaint line (specific URL not detailed in sources)", "In-person: Local ombudsman offices across the state"],
    "processing_time": "Complaint resolution varies; volunteer certification application takes 4-6 weeks.",
    "waitlist": null,
    "forms": ["State Form 49669 (Notice of Transfer or Discharge)", "State Form 49831 (Notice of Transfer or Discharge Request for Hearing)"],
    "documents": ["No specific documents required for residents/families to contact; provide details of concern or complaint."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to Indiana nursing homes and licensed assisted living facilities; does not cover home care services despite state statute mandate (unfunded).",
    "regional_variations": "Network of local offices across the state with staff and volunteers; services delivered regionally but uniform in scope.",
    "offices_or_providers": ["Local ombudsman offices statewide; central office in Indianapolis."]
  },
  "official_source": "https://www.in.gov/ombudsman/long-term-care-ombudsman/",
  "gotchas": ["Not for home care or in-home services (state mandate exists but unfunded; federal law limits to facilities).", "Services are free and confidential but resident-directed—ombudsman acts on resident's wishes.", "Anyone can contact (residents, families, staff, community), but advocacy focuses on facility residents.", "Volunteering has separate requirements (background check, training); not the same as receiving services."],
  "data_shape_notes": "no income test; facility-resident only; advocacy-focused (not financial aid or direct services); delivered via statewide volunteer network."
}
